# Production-scale multimodal RAG with error handling and monitoring
import logging
from typing import List, Dict
import numpy as np
from datetime import datetime

class ProductionMultimodalRAG:
    def __init__(self, vector_store, embedding_models, max_retries=3):
        self.vector_store = vector_store
        self.embedding_models = embedding_models
        self.max_retries = max_retries
        self.logger = logging.getLogger('MultimodalRAG')
        self.metrics = {
            'total_queries': 0,
            'retrieval_latency': [],
            'embedding_failures': 0
        }

    def retrieve_multimodal_context(self, cricket_query: str, 
                                     user_images: List[str],
                                     user_tables: List[Dict]) -> Dict:
        """Retrieve context from text, images, and tables with fault tolerance."""
        self.metrics['total_queries'] += 1
        start_time = datetime.now()

        try:
            # Embed text query with retry logic
            text_embedding = self._embed_with_retry(
                cricket_query, 
                model_type='text',
                retries=self.max_retries
            )

            # Embed images in parallel
            image_embeddings = []
            for img_path in user_images:
                try:
                    img_emb = self.embedding_models['image'].encode(img_path)
                    image_embeddings.append(img_emb)
                except Exception as e:
                    self.logger.warning(f"Image embedding failed: {img_path}. Error: {e}")
                    self.metrics['embedding_failures'] += 1

            # Embed table structures
            table_embeddings = []
            for table_data in user_tables:
                try:
                    table_str = self._table_to_string(table_data)
                    table_emb = self.embedding_models['table'].encode(table_str)
                    table_embeddings.append(table_emb)
                except Exception as e:
                    self.logger.error(f"Table embedding failed: {e}")

            # Fuse embeddings using weighted combination
            fused_embedding = self._fuse_embeddings(
                text_embedding,
                image_embeddings,
                table_embeddings,
                weights={'text': 0.5, 'image': 0.25, 'table': 0.25}
            )

            # Retrieve from vector store with timeout
            results = self.vector_store.search(
                query_vector=fused_embedding,
                top_k=10,
                timeout_seconds=2.0
            )

            latency = (datetime.now() - start_time).total_seconds()
            self.metrics['retrieval_latency'].append(latency)

            # Log performance metrics
            if latency > 1.0:
                self.logger.warning(f"High latency detected: {latency:.2f}s for query: {cricket_query[:50]}")

            return {
                'text_results': results.get('text', []),
                'image_results': results.get('images', []),
                'table_results': results.get('tables', []),
                'fused_embedding': fused_embedding,
                'retrieval_latency': latency,
                'timestamp': start_time.isoformat()
            }

        except Exception as e:
            self.logger.error(f"Retrieval failed for query: {cricket_query}. Error: {e}")
            raise

    def _embed_with_retry(self, text: str, model_type: str, retries: int) -> np.ndarray:
        """Embed text with exponential backoff retry logic."""
        for attempt in range(retries):
            try:
                return self.embedding_models[model_type].encode(text)
            except Exception as e:
                if attempt == retries - 1:
                    self.metrics['embedding_failures'] += 1
                    raise
                wait_time = 2 ** attempt
                self.logger.warning(f"Embedding retry {attempt + 1}/{retries}. Waiting {wait_time}s")

    def _fuse_embeddings(self, text_emb: np.ndarray, 
                        image_embs: List[np.ndarray],
                        table_embs: List[np.ndarray],
                        weights: Dict) -> np.ndarray:
        """Fuse multimodal embeddings using weighted averaging."""
        fused = text_emb * weights['text']

        if image_embs:
            avg_image_emb = np.mean(image_embs, axis=0)
            fused += avg_image_emb * weights['image']

        if table_embs:
            avg_table_emb = np.mean(table_embs, axis=0)
            fused += avg_table_emb * weights['table']

        # L2 normalize
        return fused / (np.linalg.norm(fused) + 1e-8)

    def _table_to_string(self, table_data: Dict) -> str:
        """Convert table dictionary to embedable string representation."""
        rows = []
        for key, value in table_data.items():
            rows.append(f"{key}: {value}")
        return " ".join(rows)

    def get_metrics(self) -> Dict:
        """Return system performance metrics for monitoring."""
        avg_latency = np.mean(self.metrics['retrieval_latency']) if self.metrics['retrieval_latency'] else 0
        return {
            'total_queries': self.metrics['total_queries'],
            'avg_retrieval_latency_ms': avg_latency * 1000,
            'embedding_failure_rate': self.metrics['embedding_failures'] / max(self.metrics['total_queries'], 1)
        }

# Usage example
rag_system = ProductionMultimodalRAG(
    vector_store=distributed_vector_db,
    embedding_models={
        'text': SentenceTransformer('all-mpnet-base-v2'),
        'image': CLIPModel(),
        'table': TableEncoder()
    }
)

results = rag_system.retrieve_multimodal_context(
    cricket_query="batting statistics for IPL 2024",
    user_images=['scorecard.jpg'],
    user_tables=[{'team': 'CSK', 'runs': 180, 'wickets': 7}]
)
print(f"Retrieved {len(results['text_results'])} text results in {results['retrieval_latency']:.3f}s")
